"use strict";(self.webpackChunkmy_page=self.webpackChunkmy_page||[]).push([[78117],{22861:(e,a,i)=>{i.r(a),i.d(a,{assets:()=>c,contentTitle:()=>r,default:()=>l,frontMatter:()=>s,metadata:()=>o,toc:()=>d});const o=JSON.parse('{"id":"czysty-kod/powstawanie-projektu","title":"Rozdzia\u0142 12: Powstawanie projektu","description":"Streszczenie: Rozdzia\u0142 12: Powstawanie projektu \u2014 Czysty Kod, Robert C. Martin","source":"@site/docs/czysty-kod/12-powstawanie-projektu.md","sourceDirName":"czysty-kod","slug":"/czysty-kod/powstawanie-projektu","permalink":"/docs/czysty-kod/powstawanie-projektu","draft":false,"unlisted":false,"editUrl":"https://github.com/przemyslvw/my-page/edit/master/docs/czysty-kod/12-powstawanie-projektu.md","tags":[],"version":"current","sidebarPosition":12,"frontMatter":{"sidebar_position":12,"title":"Rozdzia\u0142 12: Powstawanie projektu","description":"Streszczenie: Rozdzia\u0142 12: Powstawanie projektu \u2014 Czysty Kod, Robert C. Martin"},"sidebar":"tutorialSidebar","previous":{"title":"Rozdzia\u0142 11: Systemy","permalink":"/docs/czysty-kod/systemy"},"next":{"title":"Rozdzia\u0142 13: Wsp\xf3\u0142bie\u017cno\u015b\u0107","permalink":"/docs/czysty-kod/wspolbieznosc"}}');var n=i(74848),t=i(28453);const s={sidebar_position:12,title:"Rozdzia\u0142 12: Powstawanie projektu",description:"Streszczenie: Rozdzia\u0142 12: Powstawanie projektu \u2014 Czysty Kod, Robert C. Martin"},r=void 0,c={},d=[{value:"Rozdzia\u0142 12: Powstawanie projektu \u2013 Praktyczne streszczenie",id:"rozdzia\u0142-12-powstawanie-projektu--praktyczne-streszczenie",level:2},{value:"1. O co chodzi w tej sekcji",id:"1-o-co-chodzi-w-tej-sekcji",level:3},{value:"2. Kluczowe zasady i regu\u0142y",id:"2-kluczowe-zasady-i-regu\u0142y",level:3},{value:"3. Przyk\u0142ady kodu",id:"3-przyk\u0142ady-kodu",level:3},{value:"Eliminacja drobnej duplikacji logicznej",id:"eliminacja-drobnej-duplikacji-logicznej",level:4}];function z(e){const a={code:"code",h2:"h2",h3:"h3",h4:"h4",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,t.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.h2,{id:"rozdzia\u0142-12-powstawanie-projektu--praktyczne-streszczenie",children:"Rozdzia\u0142 12: Powstawanie projektu \u2013 Praktyczne streszczenie"}),"\n",(0,n.jsx)(a.p,{children:'W \u015bwiecie profesjonalnego tworzenia oprogramowania rzadko zdarza si\u0119, by idealny projekt powsta\u0142 w pierwszej iteracji. Rozdzia\u0142 12 ksi\u0105\u017cki "Czysty Kod" autorstwa Roberta C. Martina (zredagowany przez Jeffa Langra) skupia si\u0119 na tym, jak dzi\u0119ki czterem prostym regu\u0142om Kenta Becka pozwoli\u0107 projektowi \u201ewy\u0142oni\u0107 si\u0119\u201d w procesie pisania i refaktoryzacji kodu.'}),"\n",(0,n.jsx)(a.h3,{id:"1-o-co-chodzi-w-tej-sekcji",children:"1. O co chodzi w tej sekcji"}),"\n",(0,n.jsxs)(a.p,{children:["G\u0142\xf3wn\u0105 tez\u0105 autora jest stwierdzenie, \u017ce ",(0,n.jsx)(a.strong,{children:"dobry projekt nie jest dzie\u0142em przypadku ani jednorazowego wysi\u0142ku na pocz\u0105tku prac, lecz efektem ci\u0105g\u0142ej ewolucji opartej na testach i refaktoryzacji"})," [1, 2]. Wed\u0142ug Martina stosowanie czterech zasad prostego projektu pozwala programi\u015bcie uzyska\u0107 kod o wysokiej sp\xf3jno\u015bci i niskim sprz\u0119\u017ceniu bez konieczno\u015bci tworzenia skomplikowanych projekt\xf3w \u201ez g\xf3ry\u201d [1, 3]."]}),"\n",(0,n.jsx)(a.h3,{id:"2-kluczowe-zasady-i-regu\u0142y",children:"2. Kluczowe zasady i regu\u0142y"}),"\n",(0,n.jsx)(a.p,{children:"Kent Beck sformu\u0142owa\u0142 cztery zasady \u201eprostego projektu\u201d w kolejno\u015bci ich wa\u017cno\u015bci. Musisz je zna\u0107 na pami\u0119\u0107 i stosowa\u0107 przy ka\u017cdym commicie:"}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Zasada nr 1: System przechodzi wszystkie testy"})," \u2013 To fundament. Projekt mo\u017ce by\u0107 teoretycznie genialny, ale je\u015bli nie da si\u0119 go zweryfikowa\u0107, jest bezwarto\u015bciowy [4]. D\u0105\u017cenie do pe\u0142nej testowalno\u015bci wymusza na nas tworzenie ma\u0142ych klas o jednej odpowiedzialno\u015bci (SRP), bo takie klasy naj\u0142atwiej przetestowa\u0107 [3]."]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Zasada nr 2: Brak powt\xf3rze\u0144 (DRY \u2013 Don\u2019t Repeat Yourself)"})," \u2013 Powt\xf3rzenia to \u201ewr\xf3g publiczny nr 1\u201d [5]. Nie chodzi tylko o identyczne linie kodu, ale tak\u017ce o powielanie logiki w r\xf3\u017cnych miejscach. Ka\u017cda duplikacja to dodatkowa praca, ryzyko b\u0142\u0119du przy zmianach i niepotrzebna z\u0142o\u017cono\u015b\u0107 [5]."]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Zasada nr 3: Wyrazisto\u015b\u0107 kodu (Ekspresja intencji)"})," \u2013 Kod jest czytany znacznie cz\u0119\u015bciej ni\u017c pisany. Twoim zadaniem jest sprawienie, by czytelnik (cz\u0119sto Ty sam za kilka miesi\u0119cy) nie by\u0142 zaskoczony tym, co robi dana funkcja [6]. Wybieraj dobre nazwy, tw\xf3rz ma\u0142e modu\u0142y i trzymaj si\u0119 standardowych wzorc\xf3w projektowych [6]."]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Zasada nr 4: Minimalna liczba klas i metod"})," \u2013 Cho\u0107 d\u0105\u017cymy do ma\u0142ych jednostek, nie mo\u017cemy popa\u015b\u0107 w dogmatyzm tworzenia klas dla samego ich posiadania. System powinien by\u0107 tak ma\u0142y, jak to mo\u017cliwe, przy jednoczesnym zachowaniu testowalno\u015bci, braku powt\xf3rze\u0144 i czytelno\u015bci [7]."]}),"\n"]}),"\n",(0,n.jsx)(a.h3,{id:"3-przyk\u0142ady-kodu",children:"3. Przyk\u0142ady kodu"}),"\n",(0,n.jsx)(a.p,{children:"Refaktoryzacja w celu usuni\u0119cia powt\xf3rze\u0144 to jeden z najwa\u017cniejszych krok\xf3w w projektowaniu. Oto przyk\u0142ady z tekstu:"}),"\n",(0,n.jsx)(a.h4,{id:"eliminacja-drobnej-duplikacji-logicznej",children:"Eliminacja drobnej duplikacji logicznej"}),"\n",(0,n.jsx)(a.p,{children:"Zamiast dw\xf3ch niezale\u017cnych metod, mo\u017cna powi\u0105za\u0107 jedn\u0105 z drug\u0105:"}),"\n",(0,n.jsx)(a.pre,{children:(0,n.jsx)(a.code,{className:"language-java",children:'// Zamiast osobnych implementacji:\nint size() { /*...*/ }\nboolean isEmpty() { /* logiczna implementacja sprawdzaj\u0105ca stan */ }\n\n// Lepiej:\nboolean isEmpty() {\n  return 0 == size();\n}\n``` [8]\n\n#### Refaktoryzacja metod manipuluj\u0105cych obrazem (Przed i Po)\nAutor pokazuje, jak wydzieli\u0107 wsp\xf3ln\u0105 logik\u0119 czyszczenia zasob\xf3w, kt\xf3ra powtarza\u0142a si\u0119 w dw\xf3ch r\xf3\u017cnych metodach.\n\n**Przed refaktoryzacj\u0105:**\n```java\npublic void scaleToOneDimension(float desiredDimension, float imageDimension) {\n  if (Math.abs(desiredDimension - imageDimension) < errorThreshold)\n    return;\n  float scalingFactor = desiredDimension / imageDimension;\n  scalingFactor = (float)(Math.floor(scalingFactor * 100) * 0.01f);\n  RenderedOp newImage = ImageUtilities.getScaledImage(image, scalingFactor, scalingFactor);\n  image.dispose(); // Powt\xf3rzenie\n  System.gc();     // Powt\xf3rzenie\n  image = newImage; // Powt\xf3rzenie\n}\n\npublic synchronized void rotate(int degrees) {\n  RenderedOp newImage = ImageUtilities.getRotatedImage(image, degrees);\n  image.dispose(); // Powt\xf3rzenie\n  System.gc();     // Powt\xf3rzenie\n  image = newImage; // Powt\xf3rzenie\n}\n``` [8]\n\n**Po refaktoryzacji (wydzielenie `replaceImage`):**\n```java\npublic void scaleToOneDimension(float desiredDimension, float imageDimension) {\n  if (Math.abs(desiredDimension - imageDimension) < errorThreshold)\n    return;\n  float scalingFactor = desiredDimension / imageDimension;\n  scalingFactor = (float)(Math.floor(scalingFactor * 100) * 0.01f);\n  replaceImage(ImageUtilities.getScaledImage(image, scalingFactor, scalingFactor));\n}\n\npublic synchronized void rotate(int degrees) {\n  replaceImage(ImageUtilities.getRotatedImage(image, degrees));\n}\n\nprivate void replaceImage(RenderedOp newImage) {\n  image.dispose();\n  System.gc();\n  image = newImage;\n}\n``` [9]\n\n#### Zastosowanie wzorca Szablon Metody (Template Method)\nTo zaawansowany spos\xf3b na usuni\u0119cie duplikacji z algorytm\xf3w o podobnej strukturze.\n\n**Przed (osobne klasy z niemal identycznym kodem):**\nMetody `accrueUSDivisionVacation` i `accrueEUDivisionVacation` maj\u0105 te same kroki, r\xf3\u017cni\u0105 si\u0119 tylko detalami prawnymi [10].\n\n**Po refaktoryzacji:**\n```java\nabstract public class VacationPolicy {\n  public void accrueVacation() { // Szablon algorytmu\n    calculateBaseVacationHours();\n    alterForLegalMinimums();\n    applyToPayroll();\n  }\n\n  private void calculateBaseVacationHours() { /* ... */ };\n  abstract protected void alterForLegalMinimums(); // "Dziura" w algorytmie\n  private void applyToPayroll() { /* ... */ };\n}\n\npublic class USVacationPolicy extends VacationPolicy {\n  @Override protected void alterForLegalMinimums() {\n    // Kod specyficzny dla USA.\n  }\n}\n``` [11]\n\n### 4. Praktyczne wnioski \u2013 co zmieni\u0107 w swoim kodzie?\n\nPo lekturze tej sekcji powiniene\u015b wprowadzi\u0107 nast\u0119puj\u0105ce zmiany w swoim warsztacie:\n\n1.  **Przesta\u0144 traktowa\u0107 testy jako dodatek.** Je\u015bli Tw\xf3j projekt utrudnia pisanie test\xf3w, to znaczy, \u017ce projekt jest z\u0142y. Zacznij u\u017cywa\u0107 interfejs\xf3w i wstrzykiwania zale\u017cno\u015bci (DI), aby odizolowa\u0107 klasy i umo\u017cliwi\u0107 ich \u0142atwe sprawdzanie [3].\n2.  **Zatrzymaj si\u0119 po ka\u017cdej drobnej zmianie.** Nie czekaj na \u201edzie\u0144 sprz\u0105tania kodu\u201d. Gdy tylko dodasz now\u0105 funkcjonalno\u015b\u0107, sp\xf3jrz na projekt i zadaj sobie pytanie: \u201eCzy w\u0142a\u015bnie go nie zepsu\u0142em?\u201d. Je\u015bli tak \u2013 napraw to od razu [2].\n3.  **B\u0105d\u017a bezlitosny dla powt\xf3rze\u0144.** Je\u015bli widzisz podobne fragmenty kodu w dw\xf3ch miejscach, wydziel je do metody. Je\u015bli widzisz podobne algorytmy w klasach, zastosuj wzorzec *Template Method* lub *Strategy* [11, 12].\n4.  **Zainwestuj w nazewnictwo.** Nazwa funkcji powinna opowiada\u0107 histori\u0119. Je\u015bli nazwa klasy jest zbyt og\xf3lna (np. `Manager`), prawdopodobnie ma ona zbyt wiele odpowiedzialno\u015bci i narusza SRP [6].\n5.  **Nie projektuj na zapas (YAGNI).** Unikaj tworzenia skomplikowanych hierarchii klas tylko dlatego, \u017ce \u201emo\u017ce si\u0119 kiedy\u015b przydadz\u0105\u201d. Trzymaj system tak ma\u0142ym, jak to mo\u017cliwe, dop\xf3ki testy i brak powt\xf3rze\u0144 s\u0105 zachowane [7].\n\nPami\u0119taj: **Uwaga jest najcenniejszym zasobem programisty.** Po\u015bwi\u0119\u0107 j\u0105 na to, by Tw\xf3j kod by\u0142 czytelny dla innych, bo to Ty b\u0119dziesz t\u0105 osob\u0105, kt\xf3ra wr\xf3ci do niego za p\xf3\u0142 roku [6, 7].\n'})})]})}function l(e={}){const{wrapper:a}={...(0,t.R)(),...e.components};return a?(0,n.jsx)(a,{...e,children:(0,n.jsx)(z,{...e})}):z(e)}},28453:(e,a,i)=>{i.d(a,{R:()=>s,x:()=>r});var o=i(96540);const n={},t=o.createContext(n);function s(e){const a=o.useContext(t);return o.useMemo((function(){return"function"==typeof e?e(a):{...a,...e}}),[a,e])}function r(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),o.createElement(t.Provider,{value:a},e.children)}}}]);